     1→/**
     2→ * ConvergioEdu Conversation Flow Component
     3→ *
     4→ * The central conversation-first interface that:
     5→ * 1. Shows character selection with photos and introductions
     6→ * 2. Routes student messages to appropriate characters
     7→ * 3. Supports seamless handoffs between characters
     8→ * 4. Offers both text and voice modes for Coach and Buddy
     9→ *
    10→ * Part of I-01: Conversation-First Main Flow
    11→ * Related: #24 MirrorBuddy Issue, #33 Conversation UX, ManifestoEdu.md
    12→ */
    13→
    14→'use client';
    15→
    16→import { useState, useRef, useEffect, useCallback, useMemo } from 'react';
    17→import { motion, AnimatePresence, useReducedMotion } from 'framer-motion';
    18→import {
    19→  Send,
    20→  Mic,
    21→  MicOff,
    22→  Loader2,
    23→  Volume2,
    24→  VolumeX,
    25→} from 'lucide-react';
    26→import { Button } from '@/components/ui/button';
    27→import { cn } from '@/lib/utils';
    28→import { useSettingsStore } from '@/lib/stores/app-store';
    29→import { logger } from '@/lib/logger';
    30→import { useConversationFlowStore } from '@/lib/stores/conversation-flow-store';
    31→import type { ExtendedStudentProfile } from '@/types';
    32→// Tool integration - T-15
    33→import { ToolButtons } from './tool-buttons';
    34→import { ToolPanel } from '@/components/tools/tool-panel';
    35→import type { ToolType, ToolState } from '@/types/tools';
    36→import { ToolMaestroSelectionDialog } from './tool-maestro-selection-dialog';
    37→import { getMaestroById } from '@/data/maestri';
    38→import type { MaestroFull } from '@/data/maestri';
    39→// Extracted hooks and helpers
    40→import { useToolSSE } from './hooks/use-tool-sse';
    41→import { useConversationInactivity } from './hooks/use-conversation-inactivity';
    42→import { useMessageSender } from './hooks/use-message-sender';
    43→import { getOrCreateUserId, endConversationWithSummary } from './utils/conversation-helpers';
    44→
    45→// Map OpenAI function names to ToolType
    46→const FUNCTION_NAME_TO_TOOL_TYPE: Record<string, ToolType> = {
    47→  create_mindmap: 'mindmap',
    48→  create_quiz: 'quiz',
    49→  create_demo: 'demo',
    50→  web_search: 'search',
    51→  create_flashcards: 'flashcard',
    52→  create_diagram: 'diagram',
    53→  create_timeline: 'timeline',
    54→  create_summary: 'summary',
    55→  open_student_summary: 'summary',
    56→};
    57→// Sub-components
    58→import {
    59→  CharacterAvatar,
    60→  MessageBubble,
    61→  HandoffBanner,
    62→  ConversationHeader,
    63→  VoiceCallOverlay,
    64→  CHARACTER_AVATARS,
    65→} from './components';
    66→
    67→// Re-export CharacterCard for external use
    68→export { CharacterCard } from './components';
    69→
    70→// ============================================================================
    71→// MAIN COMPONENT
    72→// ============================================================================
    73→
    74→export function ConversationFlow() {
    75→  const [inputValue, setInputValue] = useState('');
    76→  const [isLoading, setIsLoading] = useState(false);
    77→  const [isMuted, setIsMuted] = useState(false);
    78→  const [isVoiceActive, setIsVoiceActive] = useState(false);
    79→  const [activeTool, setActiveTool] = useState<ToolState | null>(null);
    80→  const [isToolMinimized, setIsToolMinimized] = useState(false);
    81→  const [voiceSessionId, setVoiceSessionId] = useState<string | null>(null);
    82→  const [showMaestroDialog, setShowMaestroDialog] = useState(false);
    83→  const [pendingToolType, setPendingToolType] = useState<ToolType | null>(null);
    84→  const messagesEndRef = useRef<HTMLDivElement>(null);
    85→  const inputRef = useRef<HTMLInputElement>(null);
    86→  const _prefersReducedMotion = useReducedMotion(); // For future accessibility features
    87→
    88→  // Stores
    89→  const { studentProfile } = useSettingsStore();
    90→  const {
    91→    isActive,
    92→    mode,
    93→    activeCharacter,
    94→    messages,
    95→    pendingHandoff,
    96→    characterHistory,
    97→    sessionId,
    98→    conversationsByCharacter,
    99→    startConversation,
   100→    endConversation: _endConversation, // Available for future explicit end
   101→    addMessage,
   102→    setMode,
   103→    switchToCoach,
   104→    switchToBuddy,
   105→    goBack,
   106→    acceptHandoff,
   107→    dismissHandoff,
   108→    suggestHandoff,
   109→    routeMessage,
   110→    switchToCharacter: _switchToCharacter, // Used internally via specific switch functions
   111→  } = useConversationFlowStore();
   112→
   113→  // Extended profile for routing - memoized to avoid unnecessary re-renders
   114→  const extendedProfile: ExtendedStudentProfile = useMemo(() => ({
   115→    ...studentProfile,
   116→    learningDifferences: studentProfile.learningDifferences || [],
   117→    preferredCoach: studentProfile.preferredCoach,
   118→    preferredBuddy: studentProfile.preferredBuddy,
   119→  }), [studentProfile]);
   120→
   121→  // Handle tool request from ToolButtons - show maestro selection dialog
   122→  const handleToolRequest = useCallback((toolType: ToolType) => {
   123→    if (isLoading) return;
   124→
   125→    // Check for pending tool request in sessionStorage (from maestri-grid)
   126→    const pendingRequest = sessionStorage.getItem('pendingToolRequest');
   127→    if (pendingRequest) {
   128→      try {
   129→        const parsed = JSON.parse(pendingRequest);
   130→        // Validate parsed object has expected properties
   131→        if (typeof parsed !== 'object' || parsed === null) {
   132→          throw new Error('Invalid pendingToolRequest format');
   133→        }
   134→        const { tool, maestroId } = parsed;
   135→        if (typeof tool !== 'string' || typeof maestroId !== 'string') {
   136→          throw new Error('Missing tool or maestroId in pendingToolRequest');
   137→        }
   138→        if (tool === toolType && maestroId) {
   139→          // Use maestro from pending request - fetch full object for type safety
   140→          const maestro = getMaestroById(maestroId);
   141→          if (maestro) {
   142→            sessionStorage.removeItem('pendingToolRequest');
   143→            handleMaestroSelected(maestro, toolType);
   144→            return;
   145→          }
   146→        }
   147→      } catch (error) {
   148→        logger.error('Failed to parse pendingToolRequest', { error });
   149→        sessionStorage.removeItem('pendingToolRequest'); // Clean up invalid data
   150→      }
   151→    }
   152→
   153→    // Show maestro selection dialog
   154→    setPendingToolType(toolType);
   155→    setShowMaestroDialog(true);
   156→  }, [isLoading]);
   157→
   158→  // Handle maestro selection and create tool
   159→  const handleMaestroSelected = useCallback(async (maestro: MaestroFull, toolType: ToolType) => {
   160→    if (isLoading) return;
   161→
   162→    // Create tool prompts based on type
   163→    const toolPrompts: Record<ToolType, string> = {
   164→      mindmap: 'Crea una mappa mentale su questo argomento',
   165→      quiz: 'Crea un quiz per verificare la mia comprensione',
   166→      flashcard: 'Crea delle flashcard per memorizzare',
   167→      demo: 'Crea una demo interattiva per visualizzare',
   168→      search: 'Cerca risorse educative su questo argomento',
   169→      webcam: 'Voglio scattare una foto',
   170→      diagram: 'Crea un diagramma',
   171→      timeline: 'Crea una linea del tempo',
   172→      summary: 'Crea un riassunto',
   173→      formula: 'Mostra la formula',
   174→      chart: 'Crea un grafico',
   175→      pdf: 'Analizza il PDF',
   176→      homework: 'Aiutami con i compiti',
   177→    };
   178→
   179→    const toolPrompt = toolPrompts[toolType] || `Crea ${toolType}`;
   180→    setInputValue('');
   181→    setIsLoading(true);
   182→
   183→    addMessage({ role: 'user', content: toolPrompt });
   184→
   185→    // Create initial tool state
   186→    const newTool: ToolState = {
   187→      id: `tool-${Date.now()}`,
   188→      type: toolType,
   189→      status: 'initializing',
   190→      progress: 0,
   191→      content: null,
   192→      createdAt: new Date(),
   193→    };
   194→    setActiveTool(newTool);
   195→
   196→    try {
   197→      const response = await fetch('/api/chat', {
   198→        method: 'POST',
   199→        headers: { 'Content-Type': 'application/json' },
   200→        body: JSON.stringify({
   201→          messages: [
   202→            { role: 'system', content: maestro.systemPrompt },
   203→            ...messages
   204→              .filter((m) => m.role !== 'system')
   205→              .map((m) => ({ role: m.role, content: m.content })),
   206→            { role: 'user', content: toolPrompt },
   207→          ],
   208→          maestroId: maestro.id,
   209→          requestedTool: toolType,
   210→          enableMemory: true, // ADR 0021: Enable conversational memory injection
   211→        }),
   212→      });
   213→
   214→      if (!response.ok) throw new Error('Failed to get response');
   215→      const data = await response.json();
   216→
   217→      const assistantContent = data.content || data.message || '';
   218→      addMessage({ role: 'assistant', content: assistantContent });
   219→
   220→      // Update tool state based on response
   221→      if (data.toolCalls?.length > 0) {
   222→        const toolCall = data.toolCalls[0];
   223→        // Map function name (create_quiz) to tool type (quiz)
   224→        const mappedToolType = FUNCTION_NAME_TO_TOOL_TYPE[toolCall.type] || toolType;
   225→        // Extract actual data from result object
   226→        const toolContent = toolCall.result?.data || toolCall.result || toolCall.arguments;
   227→        setActiveTool({
   228→          ...newTool,
   229→          type: mappedToolType,
   230→          status: 'completed',
   231→          progress: 1,
   232→          content: toolContent,
   233→        });
   234→      } else {
   235→        // No tool was created, clear the state
   236→        setActiveTool(null);
   237→      }
   238→    } catch (error) {
   239→      logger.error('Tool request error', { error });
   240→      addMessage({
   241→        role: 'assistant',
   242→        content: 'Mi dispiace, non sono riuscito a creare lo strumento. Riprova?',
   243→      });
   244→      setActiveTool({
   245→        ...newTool,
   246→        status: 'error',
   247→        error: 'Errore nella creazione dello strumento',
   248→      });
   249→    } finally {
   250→      setIsLoading(false);
   251→    }
   252→  }, [isLoading, messages, addMessage]);
   253→
   254→  // Auto-scroll to bottom
   255→  useEffect(() => {
   256→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
   257→  }, [messages]);
   258→
   259→  // Focus input when conversation starts
   260→  useEffect(() => {
   261→    if (isActive && mode === 'text') {
   262→      inputRef.current?.focus();
   263→    }
   264→  }, [isActive, mode]);
   265→
   266→  // Start conversation on mount if not active
   267→  useEffect(() => {
   268→    if (!isActive) {
   269→      startConversation(extendedProfile);
   270→    }
   271→  }, [isActive, startConversation, extendedProfile]);
   272→
   273→  // #98: Inactivity tracking and auto-summary (extracted to hook)
   274→  useConversationInactivity(isActive, activeCharacter, conversationsByCharacter);
   275→
   276→  // SSE listener for real-time tool events (extracted to hook)
   277→  useToolSSE(sessionId, setActiveTool);
   278→
   279→  // Message sending with routing and handoff detection (extracted to hook)
   280→  const { sendMessage } = useMessageSender({
   281→    activeCharacter,
   282→    messages,
   283→    extendedProfile,
   284→    conversationsByCharacter,
   285→    pendingHandoff,
   286→    routeMessage,
   287→    addMessage,
   288→    suggestHandoff,
   289→  });
   290→
   291→  /**
   292→   * Handle sending a message - orchestrates UI state and delegates to sendMessage hook.
   293→   */
   294→  const handleSend = useCallback(async () => {
   295→    if (!inputValue.trim() || isLoading || !activeCharacter) return;
   296→
   297→    const userMessage = inputValue.trim();
   298→    setInputValue('');
   299→    setIsLoading(true);
   300→    addMessage({ role: 'user', content: userMessage });
   301→
   302→    try {
   303→      await sendMessage(userMessage);
   304→    } catch (error) {
   305→      logger.error('Chat error', { error });
   306→      addMessage({
   307→        role: 'assistant',
   308→        content: 'Mi dispiace, ho avuto un problema. Puoi riprovare?',
   309→      });
   310→    } finally {
   311→      setIsLoading(false);
   312→    }
   313→  }, [inputValue, isLoading, activeCharacter, addMessage, sendMessage]);
   314→
   315→  /**
   316→   * Handle key press in input.
   317→   */
   318→  const handleKeyPress = (e: React.KeyboardEvent) => {
   319→    if (e.key === 'Enter' && !e.shiftKey) {
   320→      e.preventDefault();
   321→      handleSend();
   322→    }
   323→  };
   324→
   325→  /**
   326→   * Handle voice mode toggle (for input area).
   327→   */
   328→  const handleVoiceToggle = () => {
   329→    if (mode === 'voice') {
   330→      setMode('text');
   331→    } else {
   332→      setMode('voice');
   333→    }
   334→  };
   335→
   336→  /**
   337→   * Handle voice call (full voice conversation).
   338→   */
   339→  const handleVoiceCall = useCallback(async () => {
   340→    if (isVoiceActive) {
   341→      // #98: End voice call and generate summary
   342→      setIsVoiceActive(false);
   343→      setMode('text');
   344→
   345→      // Generate summary for voice call
   346→      const userId = getOrCreateUserId();
   347→      const conversationId = activeCharacter ? conversationsByCharacter[activeCharacter.id]?.conversationId : null;
   348→      if (userId && conversationId) {
   349→        logger.info('Ending voice call, generating summary', { conversationId });
   350→        await endConversationWithSummary(conversationId);
   351→      }
   352→    } else {
   353→      // Start voice call
   354→      setIsVoiceActive(true);
   355→      setMode('voice');
   356→      // Voice session will be started by VoiceCallOverlay
   357→      // This is a placeholder - Issue #34 tracks voice WebSocket issues
   358→    }
   359→  }, [isVoiceActive, setMode, activeCharacter, conversationsByCharacter]);
   360→
   361→  /**
   362→   * Handle accepting handoff (async to properly end previous conversation).
   363→   */
   364→  const handleAcceptHandoff = async () => {
   365→    await acceptHandoff(extendedProfile);
   366→  };
   367→
   368→  /**
   369→   * Handle manual character switches (async to properly end previous conversation).
   370→   */
   371→  const handleSwitchToCoach = async () => await switchToCoach(extendedProfile);
   372→  const handleSwitchToBuddy = async () => await switchToBuddy(extendedProfile);
   373→  const handleGoBack = () => goBack(extendedProfile); // Sync: only navigates history
   374→
   375→  // Render idle state (shouldn't happen with auto-start)
   376→  if (!isActive || !activeCharacter) {
   377→    return (
   378→      <div className="flex items-center justify-center h-full">
   379→        <Button onClick={() => startConversation(extendedProfile)}>
   380→          Inizia una conversazione
   381→        </Button>
   382→      </div>
   383→    );
   384→  }
   385→
   386→  // Video conference layout when tool is active (Issue #36)
   387→  const hasActiveTool = activeTool && activeTool.status !== 'error';
   388→
   389→  return (
   390→    <div className="relative flex flex-col h-[calc(100vh-200px)] max-h-[700px] bg-white dark:bg-slate-900 rounded-2xl shadow-xl overflow-hidden">
   391→      {/* Voice call overlay */}
   392→      <AnimatePresence>
   393→        {isVoiceActive && activeCharacter && (
   394→          <VoiceCallOverlay
   395→            character={activeCharacter}
   396→            onEnd={handleVoiceCall}
   397→            onSessionIdChange={setVoiceSessionId}
   398→          />
   399→        )}
   400→      </AnimatePresence>
   401→
   402→      {/* Header with character info and voice call button - 10% */}
   403→      <ConversationHeader
   404→        currentCharacter={activeCharacter}
   405→        onSwitchToCoach={handleSwitchToCoach}
   406→        onSwitchToBuddy={handleSwitchToBuddy}
   407→        onGoBack={handleGoBack}
   408→        canGoBack={characterHistory.length > 1}
   409→        isVoiceActive={isVoiceActive}
   410→        onVoiceCall={handleVoiceCall}
   411→      />
   412→
   413→      {/* Handoff suggestion */}
   414→      <AnimatePresence>
   415→        {pendingHandoff && (
   416→          <HandoffBanner
   417→            suggestion={pendingHandoff}
   418→            onAccept={handleAcceptHandoff}
   419→            onDismiss={dismissHandoff}
   420→          />
   421→        )}
   422→      </AnimatePresence>
   423→
   424→      {/* Main content area - switches between chat-first and tool-first layouts */}
   425→      {hasActiveTool ? (
   426→        /* VIDEO CONFERENCE LAYOUT: Tool takes center stage (Issue #36) */
   427→        <div className="flex-1 flex flex-col overflow-hidden">
   428→          {/* Tool panel - 70% of remaining space */}
   429→          <div className="flex-[7] overflow-auto border-b border-slate-200 dark:border-slate-700">
   430→            <ToolPanel
   431→              tool={activeTool}
   432→              maestro={activeCharacter ? {
   433→                name: activeCharacter.name,
   434→                avatar: CHARACTER_AVATARS[activeCharacter.id] || '/avatars/default.jpg',
   435→                color: activeCharacter.color,
   436→              } : null}
   437→              onClose={() => setActiveTool(null)}
   438→              isMinimized={isToolMinimized}
   439→              onToggleMinimize={() => setIsToolMinimized(!isToolMinimized)}
   440→              embedded={true}
   441→              sessionId={voiceSessionId}
   442→            />
   443→          </div>
   444→
   445→          {/* Mini chat - 15% of remaining space */}
   446→          <div
   447→            className="flex-[1.5] overflow-y-auto p-2 bg-slate-50 dark:bg-slate-800/50"
   448→            role="log"
   449→            aria-live="polite"
   450→            aria-label="Messaggi recenti"
   451→          >
   452→            {/* Show only last 3 messages in mini view */}
   453→            {messages.slice(-3).map((message) => (
   454→              <div
   455→                key={message.id}
   456→                className={cn(
   457→                  'text-xs py-1 px-2 rounded mb-1',
   458→                  message.role === 'user'
   459→                    ? 'bg-accent-themed/10 text-right'
   460→                    : 'bg-slate-200 dark:bg-slate-700'
   461→                )}
   462→              >
   463→                <span className="font-medium">
   464→                  {message.role === 'user' ? 'Tu' : activeCharacter?.name}:
   465→                </span>{' '}
   466→                {message.content.substring(0, 80)}
   467→                {message.content.length > 80 && '...'}
   468→              </div>
   469→            ))}
   470→            {isLoading && (
   471→              <div className="text-xs py-1 px-2 flex items-center gap-1">
   472→                <Loader2 className="w-3 h-3 animate-spin" />
   473→                <span>{activeCharacter?.name} sta pensando...</span>
   474→              </div>
   475→            )}
   476→          </div>
   477→        </div>
   478→      ) : (
   479→        /* NORMAL LAYOUT: Chat takes full space */
   480→        <div
   481→          className="flex-1 overflow-y-auto p-4"
   482→          role="log"
   483→          aria-live="polite"
   484→          aria-label="Messaggi della conversazione"
   485→        >
   486→          {messages.map((message) => (
   487→            <MessageBubble
   488→              key={message.id}
   489→              message={message}
   490→              activeCharacter={
   491→                message.role === 'assistant' ? activeCharacter : null
   492→              }
   493→            />
   494→          ))}
   495→          {isLoading && (
   496→            <motion.div
   497→              initial={{ opacity: 0 }}
   498→              animate={{ opacity: 1 }}
   499→              className="flex gap-3 mb-4"
   500→            >
   501→              <CharacterAvatar character={activeCharacter} size="sm" />
   502→              <div className="px-4 py-3 bg-slate-100 dark:bg-slate-800 rounded-2xl rounded-bl-md">
   503→                <Loader2 className="w-5 h-5 animate-spin text-slate-500" />
   504→              </div>
   505→            </motion.div>
   506→          )}
   507→          <div ref={messagesEndRef} />
   508→        </div>
   509→      )}
   510→
   511→      {/* Input area - 5% */}
   512→      <div className="p-4 border-t border-slate-200 dark:border-slate-700">
   513→        <div className="flex items-center gap-2">
   514→          {/* Tool buttons - quick access to educational tools */}
   515→          <ToolButtons
   516→            onToolRequest={handleToolRequest}
   517→            disabled={isLoading}
   518→            activeToolId={activeTool?.id}
   519→          />
   520→          <input
   521→            ref={inputRef}
   522→            type="text"
   523→            value={inputValue}
   524→            onChange={(e) => setInputValue(e.target.value)}
   525→            onKeyDown={handleKeyPress}
   526→            placeholder={`Scrivi a ${activeCharacter.name}...`}
   527→            aria-label={`Scrivi un messaggio a ${activeCharacter.name}`}
   528→            className="flex-1 px-4 py-3 bg-slate-100 dark:bg-slate-800 rounded-xl border-0 focus:ring-2 focus:ring-accent-themed outline-none text-slate-900 dark:text-white placeholder:text-slate-500"
   529→            disabled={isLoading}
   530→          />
   531→          <Button
   532→            variant="ghost"
   533→            size="icon"
   534→            onClick={() => setIsMuted(!isMuted)}
   535→            aria-label={isMuted ? 'Attiva audio' : 'Disattiva audio'}
   536→            aria-pressed={isMuted}
   537→          >
   538→            {isMuted ? (
   539→              <VolumeX className="w-5 h-5" />
   540→            ) : (
   541→              <Volume2 className="w-5 h-5" />
   542→            )}
   543→          </Button>
   544→          <Button
   545→            variant="ghost"
   546→            size="icon"
   547→            onClick={handleVoiceToggle}
   548→            aria-label={mode === 'voice' ? 'Passa al testo' : 'Passa alla voce'}
   549→            aria-pressed={mode === 'voice'}
   550→            className={cn(mode === 'voice' && 'bg-red-100 text-red-600')}
   551→          >
   552→            {mode === 'voice' ? (
   553→              <MicOff className="w-5 h-5" />
   554→            ) : (
   555→              <Mic className="w-5 h-5" />
   556→            )}
   557→          </Button>
   558→          <Button
   559→            size="icon"
   560→            onClick={handleSend}
   561→            disabled={!inputValue.trim() || isLoading}
   562→            aria-label="Invia messaggio"
   563→            className="bg-accent-themed hover:bg-accent-themed/90"
   564→          >
   565→            <Send className="w-5 h-5" aria-hidden="true" />
   566→          </Button>
   567→        </div>
   568→      </div>
   569→
   570→      {/* Maestro Selection Dialog */}
   571→      <ToolMaestroSelectionDialog
   572→        isOpen={showMaestroDialog}
   573→        toolType={pendingToolType || 'mindmap'}
   574→        onSelect={(maestro) => {
   575→          if (pendingToolType) {
   576→            handleMaestroSelected(maestro, pendingToolType);
   577→          }
   578→          setShowMaestroDialog(false);
   579→          setPendingToolType(null);
   580→        }}
   581→        onClose={() => {
   582→          setShowMaestroDialog(false);
   583→          setPendingToolType(null);
   584→        }}
   585→      />
   586→    </div>
   587→  );
   588→}
   589→

