    30→// Valid material types
    31→const VALID_MATERIAL_TYPES: MaterialType[] = [
    32→  'mindmap',
    33→  'quiz',
    34→  'flashcard',
    35→  'demo',
    36→  'webcam',
    37→  'pdf',
