    67→  collectionId?: string | null;
    68→  tagIds?: string[];
    69→}
    70→
    71→/**
    72→ * GET /api/materials
    73→ * List materials for current user with optional filters
    74→ */
    75→export async function GET(request: NextRequest) {
    76→  try {
    77→    // Auth check - prefer cookie, fallback to query param for backwards compatibility
    78→    const cookieStore = await cookies();
    79→    const cookieUserId = cookieStore.get('convergio-user-id')?.value;
    80→
    81→    const { searchParams } = new URL(request.url);
    82→    const queryUserId = searchParams.get('userId');
    83→    const userId = cookieUserId || queryUserId;
    84→
    85→    const toolType = searchParams.get('toolType');
    86→    const status = searchParams.get('status') || 'active';
    87→    const limit = parseInt(searchParams.get('limit') || '50', 10);
    88→    const offset = parseInt(searchParams.get('offset') || '0', 10);
    89→
    90→    if (!userId) {
    91→      return NextResponse.json(
    92→        { error: 'Unauthorized' },
    93→        { status: 401 }
    94→      );
    95→    }
    96→
    97→    // Build where clause with filters
    98→    const collectionId = searchParams.get('collectionId');
    99→    const tagId = searchParams.get('tagId');
   100→    const search = searchParams.get('search');
   101→    const subject = searchParams.get('subject');
   102→
   103→    const where: Record<string, unknown> = { userId, status };
   104→    if (toolType && VALID_MATERIAL_TYPES.includes(toolType as MaterialType)) {
   105→      where.toolType = toolType;
   106→    }
   107→    if (collectionId) {
   108→      where.collectionId = collectionId;
   109→    }
   110→    if (tagId) {
   111→      where.tags = { some: { tagId } };
   112→    }
   113→    if (subject) {
   114→      where.subject = subject;
   115→    }
   116→    if (search) {
   117→      // Full-text search on searchableText and title
   118→      where.OR = [
   119→        { searchableText: { contains: search, mode: 'insensitive' } },
   120→        { title: { contains: search, mode: 'insensitive' } },
   121→      ];
   122→    }
   123→
   124→    const [materials, total] = await Promise.all([
   125→      prisma.material.findMany({
   126→        where,
   127→        orderBy: { createdAt: 'desc' },
   128→        take: Math.min(limit, 100),
   129→        skip: offset,
   130→        include: {
   131→          collection: {
   132→            select: { id: true, name: true, color: true },
   133→          },
   134→          tags: {
   135→            include: {
   136→              tag: { select: { id: true, name: true, color: true } },
   137→            },
   138→          },
   139→        },
   140→      }),
   141→      prisma.material.count({ where }),
   142→    ]);
   143→
   144→    // Parse JSON content and flatten tags
   145→    const parsed = materials.map((m) => ({
   146→      ...m,
   147→      content: JSON.parse(m.content as string),
   148→      tags: m.tags.map((mt) => mt.tag),
   149→    }));
   150→
   151→    return NextResponse.json({
   152→      materials: parsed,
   153→      total,
   154→      limit,
   155→      offset,
   156→    });
   157→  } catch (error) {
   158→    logger.error('Failed to fetch materials', { error: String(error) });
   159→    return NextResponse.json(
   160→      { error: 'Failed to fetch materials' },
   161→      { status: 500 }
   162→    );
   163→  }
   164→}
