   166→/**
   167→ * POST /api/materials
   168→ * Create a new material (persist tool output)
   169→ */
   170→export async function POST(request: NextRequest) {
   171→  try {
   172→    // Auth check - prefer cookie, fallback to body for backwards compatibility
   173→    const cookieStore = await cookies();
   174→    const cookieUserId = cookieStore.get('convergio-user-id')?.value;
   175→
   176→    const body: CreateMaterialRequest & { userId?: string } = await request.json();
   177→    const userId = cookieUserId || body.userId;
   178→    const { toolId, toolType, title, content, maestroId, sessionId, subject, preview, collectionId, tagIds } = body;
   179→
   180→    // Validate required fields
   181→    if (!userId || !toolId || !toolType || !title || !content) {
   182→      return NextResponse.json(
   183→        {
   184→          error: 'Missing required fields',
   185→          required: ['userId', 'toolId', 'toolType', 'title', 'content'],
   186→        },
   187→        { status: 400 }
   188→      );
   189→    }
   190→
   191→    // Validate tool type
   192→    if (!VALID_MATERIAL_TYPES.includes(toolType)) {
