   306→    }
   307→
   308→    const updateData: Record<string, unknown> = {};
   309→    if (title) updateData.title = title;
   310→    if (content) {
   311→      updateData.content = JSON.stringify(content);
   312→      // Regenerate searchable text when content changes
   313→      updateData.searchableText = generateSearchableText(
   314→        existing.toolType as ToolType,
   315→        content
   316→      );
   317→    }
   318→    if (status) updateData.status = status;
   319→    // User interaction fields (Issue #37)
   320→    if (typeof userRating === 'number' && userRating >= 1 && userRating <= 5) {
   321→      updateData.userRating = userRating;
   322→    }
   323→    if (typeof isBookmarked === 'boolean') {
   324→      updateData.isBookmarked = isBookmarked;
   325→    }
   326→    // Collection update (null = remove from collection)
   327→    if (collectionId !== undefined) {
   328→      updateData.collectionId = collectionId;
   329→    }
   330→
   331→    // Handle tag updates if provided
   332→    if (tagIds !== undefined) {
   333→      // Delete existing tags and create new ones in a transaction
   334→      await prisma.$transaction([
   335→        prisma.materialTag.deleteMany({ where: { materialId: existing.id } }),
