   347→        tags: { include: { tag: { select: { id: true, name: true, color: true } } } },
   348→      },
   349→    });
   350→
   351→    logger.info('Material patched', { toolId, fields: Object.keys(updateData), tagCount: tagIds?.length });
   352→
   353→    return NextResponse.json({
   354→      success: true,
   355→      material: {
   356→        ...updated,
   357→        tags: updated.tags.map(mt => mt.tag),
   358→        content: content || JSON.parse(updated.content),
   359→      },
   360→    });
   361→  } catch (error) {
   362→    logger.error('Failed to update material', { error: String(error) });
   363→    return NextResponse.json(
   364→      { error: 'Failed to update material' },
   365→      { status: 500 }
   366→    );
   367→  }
